from typing import Any
import numpy as np


class Solver:
    def solve(self, problem: tuple[np.ndarray, np.ndarray], **kwargs) -> Any:
        vec1, vec2 = problem
        return np.asarray(vec1, dtype=np.float64)[:, None] * np.asarray(vec2, dtype=np.float64)
